### CRUD Endpoints API
#### Overview
This API provides basic CRUD (Create, Read, Update, Delete) operations. It uses Flask, a lightweight Python web framework.

#### Requirements
- Python 3.8+
- Flask 2.0+

#### Implementation
```python
from flask import Flask, jsonify, request

app = Flask(__name__)

# Sample in-memory data store
data_store = {
    1: {"name": "John Doe", "age": 30},
    2: {"name": "Jane Doe", "age": 25}
}

# Create endpoint
@app.route('/users', methods=['POST'])
def create_user():
    """Create a new user."""
    new_user = request.json
    new_user_id = max(data_store.keys()) + 1 if data_store else 1
    data_store[new_user_id] = new_user
    return jsonify({"id": new_user_id, **new_user}), 201

# Read endpoint (get all users)
@app.route('/users', methods=['GET'])
def get_all_users():
    """Get all users."""
    return jsonify(list(data_store.values()))

# Read endpoint (get user by id)
@app.route('/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    """Get a user by id."""
    if user_id in data_store:
        return jsonify(data_store[user_id])
    return jsonify({"error": "User not found"}), 404

# Update endpoint
@app.route('/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    """Update a user."""
    if user_id in data_store:
        updated_user = request.json
        data_store[user_id] = updated_user
        return jsonify(data_store[user_id])
    return jsonify({"error": "User not found"}), 404

# Delete endpoint
@app.route('/users/<int:user_id>', methods=['DELETE'])
def delete_user(user_id):
    """Delete a user."""
    if user_id in data_store:
        del data_store[user_id]
        return jsonify({"message": "User deleted"})
    return jsonify({"error": "User not found"}), 404

if __name__ == '__main__':
    app.run(debug=True)
